import type { HTMLAttributes, PropsWithChildren } from 'react';

import { useOverlay } from '../../../overlay-tooltip/contexts/OverlayContext.js';

/**
 * Wrapping container for the AnnotationsChart displays. Sits inside the
 * `OverlayProvider` so it can attach `overlay.overlayRef` declaratively to
 * the DOM node that defines the chart's bounds. This mirrors the pattern
 * used by other charts (PieChart, XYChart, MeterBarChart, etc.) and avoids
 * mutating the context-derived ref from a child component.
 *
 * @internal
 */
export const AnnotationsContainer = (
  props: PropsWithChildren<HTMLAttributes<HTMLDivElement>>,
) => {
  const { children, ...divProps } = props;
  const overlay = useOverlay();

  return (
    <div ref={overlay.overlayRef} {...divProps}>
      {children}
    </div>
  );
};

AnnotationsContainer.displayName = 'AnnotationsContainer';
